requestTransformation.script:
const file = context.file;
if (!file || !file.base64) {
  throw new Error('PDF file field is required.');
}

const orderNumber = String(context.body?.orderId || payload?.orderId || '').trim();
const labId = String(context.body?.LabID || payload?.LabID || '').trim();
const reportStatus = String(context.body?.reportStatus || payload?.reportStatus || '').trim();

if (!orderNumber || !labId) {
  throw new Error('orderId and LabID are required.');
}

const serviceCodesRaw = context.body?.serviceCodesJson || payload?.serviceCodesJson || '';
if (!serviceCodesRaw) {
  throw new Error('serviceCodesJson is required in this generic example until DB resolvers are available.');
}

let parsedServiceCodes;
try {
  parsedServiceCodes = JSON.parse(serviceCodesRaw);
} catch (error) {
  throw new Error('serviceCodesJson must be valid JSON.');
}

if (!Array.isArray(parsedServiceCodes) || parsedServiceCodes.length === 0) {
  throw new Error('serviceCodesJson must be a non-empty JSON array.');
}

const serviceCodes = parsedServiceCodes.map(function (value) {
  if (typeof value === 'string') {
    return { serviceCode: value.trim() };
  }
  if (value && typeof value === 'object' && value.serviceCode) {
    return { serviceCode: String(value.serviceCode).trim() };
  }
  throw new Error('Each serviceCodesJson entry must be a string or { serviceCode }.');
});

return {
  orderNumber,
  labId,
  serviceCodes,
  reportData: file.base64,
  metadata: {
    reportStatus,
    originalFileName: file.originalName,
    mimeType: file.mimeType,
    sizeBytes: file.sizeBytes
  }
};
